import * as React from "react";

import Layout from "../components/layout";
import { graphql } from "gatsby";
import PublicationComponent from "../components/PublicationComponent";

const ResearchPage = ({ data }) => {
  return (
    <Layout>
      <section className="flex flex-row flex-wrap items-center justify-center bg-slate-300">
        <h3 className="text-3xl p-5">Research</h3>
      </section>

      {/* <section>
        <h3 className="text-3xl font-semibold">Interests</h3>
        <p>

        </p>
      </section> */}

      <section className="p-2">
        <h3 className="text-3xl font-semibold">Publications</h3>
        <ol className="list-decimal list-inside">
            {data.allCvYaml.nodes.map((node) => {
                return node.publications.map((pub) => <PublicationComponent pub={pub}/>)
            })}
        </ol>
      </section>
    </Layout>
  );
};

export const query = graphql`
  query {
    allCvYaml(sort: { publications: { date: DESC } }) {
      nodes {
        publications {
          authors
          title
          journal
          arxiv_number
          arxiv_domain
          date(formatString: "YYYY")
        }
      }
    }
  }
`;

export default ResearchPage;
