import * as React from "react";

const PublicationComponent = ({ pub }) => {
  return (
    <li>
      {pub.authors}, "{pub.title}", {pub.journal},{" "}
      <a className="text-sky-600 hover:underline" href={`https://arxiv.org/abs/${pub.arxiv_number}`}>
        arXiv preprint {pub.arxiv_domain}/{pub.arxiv_number}
      </a>
      , {pub.date}
    </li>
  );
};

export default PublicationComponent;
